const fs = require('fs');
const path = require('path');

const repoRoot = path.resolve(__dirname, '..');
const foodsDir = path.join(repoRoot, 'foods');

function deepClone(v) { return JSON.parse(JSON.stringify(v)); }
function slugify(s) { return s.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, ''); }
function round1(n) { return n === null || n === undefined ? n : Math.round(n * 10) / 10; }

const allMetricKeys = [
  'saturated_fat_g','omega3_mg','polyunsaturated_fat_g','cholesterol_mg','starch_g','fibre_g','sugar_g','glycemic_index',
  'collagen_g','essential_amino_acids_score','nonessential_amino_acids_score','bioavailability_percent',
  'vitamin_a_dv','vitamin_c_dv','vitamin_d_dv','vitamin_e_dv','vitamin_k_dv','vitamin_b12_dv',
  'iron_dv','magnesium_dv','zinc_dv','calcium_dv','potassium_dv'
];

function metrics(base, overrides={}) {
  const out = Object.fromEntries(allMetricKeys.map(k => [k, null]));
  Object.assign(out, deepClone(base), deepClone(overrides));
  return out;
}

function buildContext(items) {
  return {
    pros: items.pros.map(p => ({ ...p, evidenceType: 'manual' })),
    cons: items.cons.map(c => ({ ...c, evidenceType: 'manual' }))
  };
}

