function mergeContext(baseContext, override={}) {
  const out = deepClone(baseContext);
  if (override.pros?.length) out.pros[0] = override.pros[0];
  if (override.cons?.length) out.cons[0] = override.cons[0];
  return buildContext(out);
}

function makeFood(type, tuple) {
  const [id, name, header, metricOverrides, expectedTier, contextOverride] = tuple;
  return {
    id,
    name,
    foodType: type,
    basis: { value: 100, unit: 'g' },
    header: Object.fromEntries(Object.entries(header).map(([k,v]) => [k, round1(v)])),
    metrics: metrics({}, metricOverrides),
    contextItems: mergeContext(library[type].baseContext, contextOverride || {}),
    expectedTier,
    sourceNotes: [
      'Expanded dataset sample for FoodRanked pressure-testing.',
      'Values are approximate representative placeholders for category tuning, not a clinical nutrient database.'
    ]
  };
}

let written = 0;
for (const [type, config] of Object.entries(library)) {
  for (const tuple of config.foods) {
    const food = makeFood(type, tuple);
    const outPath = path.join(foodsDir, `${slugify(food.id)}.sample.json`);
    fs.writeFileSync(outPath, JSON.stringify(food, null, 2) + '\n');
    written++;
  }
}

console.log(JSON.stringify({ status: 'ok', written }, null, 2));
